// file: config.ts
function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) throw new Error(`Missing required env var: ${name}`);
  return value;
}

// Bulk and critical email were split onto two API keys so the two traffic
// streams are distinguishable in the provider dashboard. Both keys are issued
// under the same provider account (account id "acct_7fb2").
export const BULK_KEY = requireEnv("MAIL_BULK_KEY");
export const CRITICAL_KEY = requireEnv("MAIL_CRITICAL_KEY");
export const PROVIDER_ACCOUNT = "acct_7fb2";

// file: mailer.ts
// Minimal stand-in for a transactional-email SDK (Postmark/Resend-style).
class MailProvider {
  constructor(private readonly apiKey: string) {}
  async send(msg: { to: string; subject: string; body: string }): Promise<void> {
    // A real SDK performs the HTTP call here; the provider throws a 429 when it
    // rejects a request for exceeding limits.
    void this.apiKey;
    void msg;
  }
}

export interface SendResult {
  sent: boolean;
}

/**
 * Send one email with the given API key. A 429 ("too many requests") from the
 * provider is treated as a soft failure — we return { sent: false } instead of
 * throwing, so a single send can never crash the caller.
 */
export async function sendEmail(
  apiKey: string,
  to: string,
  subject: string,
  body: string,
): Promise<SendResult> {
  const provider = new MailProvider(apiKey);
  try {
    await provider.send({ to, subject, body });
    return { sent: true };
  } catch (err) {
    const status = (err as { status?: number }).status;
    if (status === 429) return { sent: false };
    return { sent: false };
  }
}

// file: notifications.ts
import { sendEmail } from "./mailer";
import { BULK_KEY, CRITICAL_KEY } from "./config";

/**
 * Nightly marketing digest to the entire user base — potentially tens of
 * thousands of sends in a tight loop, all on the bulk key.
 */
export async function sendNightlyDigest(recipients: string[], html: string): Promise<void> {
  for (const to of recipients) {
    await sendEmail(BULK_KEY, to, "Your daily digest", html);
  }
}

/**
 * A critical security alert (e.g. an account-takeover warning) that MUST reach
 * the recipient. Moved onto a dedicated key to keep it off the bulk stream.
 */
export async function sendCriticalAlert(to: string, subject: string, body: string): Promise<void> {
  const result = await sendEmail(CRITICAL_KEY, to, subject, body);
  if (!result.sent) {
    // Best effort: note it and move on.
    console.warn(`[alert] critical alert to ${to} was not delivered`);
  }
}
